@page "/category/{CategoryName}"
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes - RecipeShare</PageTitle>

<h1>@CategoryName Recipes</h1>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

@if (recipes.Count == 0)
{
    <p class="text-muted">No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="card-text text-muted">
                            @if (recipe.Ratings.Count > 0)
                            {
                                <span>⭐ @recipe.AverageRating.ToString("F1") (@recipe.Ratings.Count ratings)</span>
                            }
                            else
                            {
                                <span>No ratings yet</span>
                            }
                        </p>
                        <a href="/recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private IReadOnlyList<RecipeShare.Models.Recipe> recipes = [];

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

@if (recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe.</p>
    <a href="/">Back to Home</a>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/category/@recipe.Category">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <p class="text-muted">Category: @recipe.Category</p>

    <StarRating RecipeId="recipe.Id" CurrentRating="recipe.AverageRating" RatingCount="recipe.Ratings.Count" />

    <h3 class="mt-4">Ingredients</h3>
    <ul class="list-group mb-4">
        @foreach (var ingredient in recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            <li class="list-group-item">@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <div class="mb-4">
        @foreach (var step in recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            <p>@step</p>
        }
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private RecipeShare.Models.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService RecipeService

<div class="my-3 p-3 border rounded">
    <h5>Rate this recipe</h5>
    <div class="d-flex align-items-center gap-2">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <button class="btn btn-link p-0 fs-3 text-decoration-none"
                    @onclick="() => SubmitRating(star)"
                    title="Rate @star stars">
                @(star <= hoveredStar ? "★" : "☆")
            </button>
        }
        <span class="ms-3 text-muted">
            @if (RatingCount > 0)
            {
                @($"⭐ {CurrentRating:F1} ({RatingCount} ratings)")
            }
            else
            {
                @("No ratings yet")
            }
        </span>
    </div>
    @if (submitted)
    {
        <div class="alert alert-success mt-2 py-1 px-2" role="alert">
            Thanks for rating!
        </div>
    }
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    [Parameter]
    public double CurrentRating { get; set; }

    [Parameter]
    public int RatingCount { get; set; }

    private int hoveredStar;
    private bool submitted;

    private void SubmitRating(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            CurrentRating = recipe.AverageRating;
            RatingCount = recipe.Ratings.Count;
        }
        hoveredStar = stars;
        submitted = true;
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">Submit Recipe</li>
    </ol>
</nav>

@if (successMessage is not null)
{
    <div class="alert alert-success" role="alert">
        @successMessage
    </div>
}

<EditForm Model="formModel" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
    <DataAnnotationsValidator />
    <ValidationSummary class="text-danger" />

    <div class="mb-3">
        <label for="title" class="form-label">Recipe Title</label>
        <InputText id="title" @bind-Value="formModel.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
        <ValidationMessage For="() => formModel.Title" class="text-danger" />
    </div>

    <div class="mb-3">
        <label for="category" class="form-label">Category</label>
        <InputSelect id="category" @bind-Value="formModel.Category" class="form-select">
            <option value="">-- Select a category --</option>
            @foreach (var cat in RecipeService.GetCategories())
            {
                <option value="@cat">@cat</option>
            }
            <option value="Other">Other</option>
        </InputSelect>
        <ValidationMessage For="() => formModel.Category" class="text-danger" />
    </div>

    <div class="mb-3">
        <label for="ingredients" class="form-label">Ingredients (one per line)</label>
        <InputTextArea id="ingredients" @bind-Value="formModel.Ingredients" class="form-control" rows="6"
                       placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" />
        <ValidationMessage For="() => formModel.Ingredients" class="text-danger" />
    </div>

    <div class="mb-3">
        <label for="steps" class="form-label">Steps (one per line)</label>
        <InputTextArea id="steps" @bind-Value="formModel.Steps" class="form-control" rows="6"
                       placeholder="1. Preheat oven to 350°F&#10;2. Mix dry ingredients&#10;3. Add wet ingredients" />
        <ValidationMessage For="() => formModel.Steps" class="text-danger" />
    </div>

    <button type="submit" class="btn btn-success">Submit Recipe</button>
</EditForm>

@code {
    private RecipeFormModel formModel = new();
    private string? successMessage;

    private void HandleSubmit()
    {
        RecipeService.AddRecipe(formModel.Title, formModel.Category, formModel.Ingredients, formModel.Steps);
        successMessage = $"Recipe \"{formModel.Title}\" submitted successfully!";
        formModel = new();
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required")]
        [System.ComponentModel.DataAnnotations.StringLength(100, ErrorMessage = "Title must be 100 characters or less")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Category is required")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Ingredients are required")]
        public string Ingredients { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Steps are required")]
        public string Steps { get; set; } = string.Empty;
    }
}

